/* Variables*/
const uint8_t msg[] 	= "VAMSI";
uint8_t* ptxbuf     	= (uint8_t*)msg;
uint8_t tx_size			= sizeof(msg);
volatile uint8_t tx_idx = 0;

uint8_t rx_buf[sizeof(msg)];
uint8_t rx_size			= sizeof(msg);
volatile uint8_t rx_idx = 0;

